// // This module implements a 16-bit DRAM cell where writing occurs on the falling edge of CLK and reading occurs on the rising edge of CLK.
module dram_cell (
    input wire [15:0] D,
    input wire RW,
    input wire CLK,
    output reg [15:0] Q
);

always @(posedge CLK) begin
    if (RW) begin
        Q <= D; // Write operation
    end else begin
        // Read operation, Q retains the stored value
        // No action needed since Q is already driven by the stored value
    end
end

endmodule
